<?php
session_start();

// Database connection (adjust credentials as needed)
$pdo = new PDO('mysql:host=localhost;dbname=your_database', 'username', 'password', [
    PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
    PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
]);

// --- Authentication check (replace with your actual auth logic) ---
if (empty($_SESSION['admin_logged_in']) || $_SESSION['admin_logged_in'] !== true) {
    http_response_code(403);
    die('Access denied. Admin authentication required.');
}

// --- CSRF Token Generation ---
function generateCsrfToken(): string
{
    if (empty($_SESSION['csrf_token'])) {
        $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
    }
    return $_SESSION['csrf_token'];
}

function validateCsrfToken(?string $token): bool
{
    return isset($_SESSION['csrf_token'])
        && $token !== null
        && hash_equals($_SESSION['csrf_token'], $token);
}

// --- Handle Deletion ---
$message = '';
$messageType = '';

if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['user_id'])) {
    // Validate CSRF token
    if (!validateCsrfToken($_POST['csrf_token'] ?? null)) {
        http_response_code(403);
        die('Invalid CSRF token. Request rejected.');
    }

    $userId = filter_input(INPUT_POST, 'user_id', FILTER_VALIDATE_INT);

    if ($userId === false || $userId === null || $userId <= 0) {
        $message = 'Invalid user ID provided.';
        $messageType = 'error';
    } else {
        // Prevent admin from deleting themselves
        if ($userId === (int)$_SESSION['admin_user_id']) {
            $message = 'You cannot delete your own account.';
            $messageType = 'error';
        } else {
            try {
                // Check if user exists before deleting
                $checkStmt = $pdo->prepare('SELECT id, username, email FROM users WHERE id = :id');
                $checkStmt->execute([':id' => $userId]);
                $user = $checkStmt->fetch();

                if (!$user) {
                    $message = 'User not found.';
                    $messageType = 'error';
                } else {
                    $deleteStmt = $pdo->prepare('DELETE FROM users WHERE id = :id');
                    $deleteStmt->execute([':id' => $userId]);

                    if ($deleteStmt->rowCount() > 0) {
                        $message = 'User "' . htmlspecialchars($user['username']) . '" (ID: ' . $userId . ') has been deleted successfully.';
                        $messageType = 'success';

                        // Regenerate CSRF token after successful action
                        unset($_SESSION['csrf_token']);
                    } else {
                        $message = 'Failed to delete user.';
                        $messageType = 'error';
                    }
                }
            } catch (PDOException $e) {
                error_log('User deletion error: ' . $e->getMessage());
                $message = 'A database error occurred. Please try again.';
                $messageType = 'error';
            }
        }
    }
}

// --- Fetch all users for display ---
$csrfToken = generateCsrfToken();

try {
    $usersStmt = $pdo->query('SELECT id, username, email, created_at FROM users ORDER BY id ASC');
    $users = $usersStmt->fetchAll();
} catch (PDOException $e) {
    error_log('User fetch error: ' . $e->getMessage());
    $users = [];
}
